use thiserror::Error;

#[derive(Error, Debug)]
pub enum ScraperError {
    #[error("HTTP request failed: {0}")]
    Http(#[from] reqwest::Error),

    #[error("CSS selector parse error: {0}")]
    Selector(String),
}

use reqwest;
use scraper::{Html, Selector};
use crate::error::ScraperError;

pub fn fetch_page(url: &str) -> Result<String, ScraperError> {
    let body = reqwest::blocking::get(url)?.text()?;
    Ok(body)
}

pub fn extract_titles(html: &str) -> Result<Vec<String>, ScraperError> {
    let doc = Html::parse_document(html);
    let sel = Selector::parse("h1, h2")
        .map_err(|e| ScraperError::Selector(format!("{:?}", e)))?;
    Ok(doc.select(&sel).map(|el| el.text().collect()).collect())
}
